import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  Room, 
  RoomEvent, 
  RemoteParticipant, 
  LocalParticipant, 
  RemoteAudioTrack, 
  DataPacket_Kind,
  RemoteTrackPublication,
  Track
} from 'livekit-client';

interface Message {
  id: string;
  speaker: 'STUDENT' | 'AI_INTERVIEWER';
  message: string;
  timestamp: string;
  type: 'text' | 'audio' | 'transcript';
}

interface LiveKitInfo {
  url: string;
  token: string;
  room_name: string;
}

interface Feedback {
  overall_score: number;
  strengths?: string[];
  improvements?: string[];
}

const LiveKitInterview: React.FC = () => {
  const { interviewId, agentId } = useParams<{ interviewId?: string; agentId?: string }>();
  const { state: authState } = useAuth();
  const navigate = useNavigate();

  const [messages, setMessages] = useState<Message[]>([]);
  const [isConnected, setIsConnected] = useState(false);
  const [sessionStarted, setSessionStarted] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [livekitInfo, setLivekitInfo] = useState<LiveKitInfo | null>(null);
  const [transcript, setTranscript] = useState<string>('');
  const [feedback, setFeedback] = useState<Feedback | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMicEnabled, setIsMicEnabled] = useState(false);

  const roomRef = useRef<Room | null>(null);
  const websocketRef = useRef<WebSocket | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  useEffect(() => {
    if (interviewId || agentId) {
      initializeSession();
    }
    return () => cleanup();
  }, [interviewId, agentId]);

  const initializeSession = async () => {
    try {
      setIsLoading(true);
      setError(null);

      const sessionId = interviewId || agentId;
      if (!sessionId) {
        throw new Error('No session ID provided');
      }

      // Check if user is authenticated
      if (!authState.user?.id) {
        throw new Error('User not authenticated');
      }

      await connectWebSocket(sessionId);
    } catch (error) {
      console.error('Failed to initialize session:', error);
      setError(error instanceof Error ? error.message : 'Failed to initialize session');
    } finally {
      setIsLoading(false);
    }
  };

  const connectWebSocket = async (sessionId: string) => {
    return new Promise<void>((resolve, reject) => {
      try {
        const wsUrl = `ws://localhost:8000/ws/${sessionId}`;
        const ws = new WebSocket(wsUrl);
        websocketRef.current = ws;

        const timeout = setTimeout(() => {
          reject(new Error('WebSocket connection timeout'));
        }, 10000); // 10 second timeout

        ws.onopen = () => {
          clearTimeout(timeout);
          console.log('WebSocket connected');
          setIsConnected(true);

          ws.send(JSON.stringify({
            type: 'join_session',
            participant_id: authState.user?.id,
            participant_name: `${authState.user?.first_name} ${authState.user?.last_name}`,
            role: 'student',
            session_type: agentId ? 'practice' : 'interview'
          }));

          resolve();
        };

        ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            handleWebSocketMessage(data);
          } catch (error) {
            console.error('Error parsing WebSocket message:', error);
          }
        };

        ws.onerror = (error) => {
          clearTimeout(timeout);
          console.error('WebSocket error:', error);
          setIsConnected(false);
          setError('WebSocket connection failed');
          reject(error);
        };

        ws.onclose = (event) => {
          console.log('WebSocket disconnected:', event.code, event.reason);
          setIsConnected(false);

          // Attempt to reconnect if not intentionally closed
          if (event.code !== 1000 && sessionStarted) {
            attemptReconnect(sessionId);
          }
        };
      } catch (error) {
        reject(error);
      }
    });
  };

  const attemptReconnect = (sessionId: string) => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }

    reconnectTimeoutRef.current = setTimeout(async () => {
      try {
        console.log('Attempting to reconnect WebSocket...');
        await connectWebSocket(sessionId);
      } catch (error) {
        console.error('Reconnection failed:', error);
        setError('Connection lost. Please refresh the page.');
      }
    }, 3000);
  };

  const handleWebSocketMessage = (data: any) => {
    try {
      switch (data.type) {
        case 'session_ready':
          console.log('Session ready:', data);
          setSessionStarted(true);
          setError(null);

          if (data.livekit_info) {
            setLivekitInfo(data.livekit_info);
            connectToLiveKitRoom(data.livekit_info);
          }
          break;

        case 'ai_response':
          console.log('AI response:', data);
          setMessages(prev => [...prev, {
            id: `ai_${Date.now()}_${Math.random()}`,
            speaker: 'AI_INTERVIEWER',
            message: data.message,
            timestamp: data.timestamp || new Date().toISOString(),
            type: 'text'
          }]);
          break;

        case 'ai_audio':
          console.log('AI audio received');
          if (data.audio_data) {
            playAudioFromBase64(data.audio_data);
          }
          break;

        case 'transcript_update':
          if (data.entry) {
            setMessages(prev => [...prev, {
              id: data.entry.id || `transcript_${Date.now()}`,
              speaker: data.entry.speaker === 'Student' ? 'STUDENT' : 'AI_INTERVIEWER',
              message: data.entry.message,
              timestamp: data.entry.timestamp || new Date().toISOString(),
              type: 'transcript'
            }]);
            setTranscript(prev => prev + '\n' + data.entry.message);
          }
          break;

        case 'interview_feedback':
          console.log('Interview feedback:', data.feedback);
          setFeedback(data.feedback);
          break;

        case 'session_ended':
          console.log('Session ended:', data);
          setSessionStarted(false);
          cleanup();
          navigate('/dashboard');
          break;

        case 'error':
          console.error('Server error:', data.message);
          setError(data.message);
          break;

        default:
          console.log('Unknown message type:', data.type);
      }
    } catch (error) {
      console.error('Error handling WebSocket message:', error);
    }
  };

  const connectToLiveKitRoom = async (livekitInfo: LiveKitInfo) => {
    try {
      console.log('Connecting to LiveKit room:', livekitInfo.room_name);

      // Disconnect existing room if any
      if (roomRef.current) {
        await roomRef.current.disconnect();
      }

      const room = new Room({
        adaptiveStream: true,
        dynacast: true,
      });

      roomRef.current = room;

      // Set up room event listeners
      room.on(RoomEvent.ParticipantConnected, handleParticipantConnected);
      room.on(RoomEvent.ParticipantDisconnected, handleParticipantDisconnected);
      room.on(RoomEvent.DataReceived, handleDataReceived);
      room.on(RoomEvent.TrackSubscribed, handleTrackSubscribed);
      room.on(RoomEvent.TrackUnsubscribed, handleTrackUnsubscribed);
      room.on(RoomEvent.Disconnected, handleRoomDisconnected);
      room.on(RoomEvent.Reconnecting, () => console.log('LiveKit reconnecting...'));
      room.on(RoomEvent.Reconnected, () => console.log('LiveKit reconnected'));

      // Connect to the room
      await room.connect(livekitInfo.url, livekitInfo.token, {
        autoSubscribe: true,
      });

      console.log('Connected to LiveKit room');

      // Enable local audio
      await enableMicrophone();

      // Start recording audio for processing
      await startAudioRecording();

    } catch (error) {
      console.error('Failed to connect to LiveKit room:', error);
      setError('Failed to connect to voice chat');
    }
  };

  const handleParticipantConnected = (participant: RemoteParticipant) => {
    console.log('Participant connected:', participant.identity);
  };

  const handleParticipantDisconnected = (participant: RemoteParticipant) => {
    console.log('Participant disconnected:', participant.identity);
  };

  const handleRoomDisconnected = (reason?: any) => {
    console.log('Room disconnected:', reason);
    setError('Voice connection lost');
  };

  const handleDataReceived = (payload: Uint8Array, participant?: RemoteParticipant) => {
    try {
      const data = JSON.parse(new TextDecoder().decode(payload));
      console.log('Data received from LiveKit:', data);

      if (data.type === 'ai_response') {
        setMessages(prev => [...prev, {
          id: `ai_livekit_${Date.now()}`,
          speaker: 'AI_INTERVIEWER',
          message: data.message,
          timestamp: data.timestamp || new Date().toISOString(),
          type: 'text'
        }]);
      }
    } catch (error) {
      console.error('Error parsing LiveKit data:', error);
    }
  };

  const handleTrackSubscribed = (
    track: RemoteAudioTrack, 
    publication: RemoteTrackPublication, 
    participant: RemoteParticipant
  ) => {
    console.log('Audio track subscribed:', participant.identity);

    if (track.kind === Track.Kind.Audio) {
      const audioElement = document.getElementById('remote-audio') as HTMLAudioElement;
      if (audioElement) {
        track.attach(audioElement);
      }
    }
  };

  const handleTrackUnsubscribed = (
    track: RemoteAudioTrack, 
    publication: RemoteTrackPublication, 
    participant: RemoteParticipant
  ) => {
    console.log('Audio track unsubscribed:', participant.identity);
    track.detach();
  };

  const enableMicrophone = async () => {
    try {
      if (roomRef.current) {
        await roomRef.current.localParticipant.setMicrophoneEnabled(true);
        setIsMicEnabled(true);
      }
    } catch (error) {
      console.error('Error enabling microphone:', error);
      setError('Failed to enable microphone');
    }
  };

  const disableMicrophone = async () => {
    try {
      if (roomRef.current) {
        await roomRef.current.localParticipant.setMicrophoneEnabled(false);
        setIsMicEnabled(false);
      }
    } catch (error) {
      console.error('Error disabling microphone:', error);
    }
  };

  const startAudioRecording = async () => {
    try {
      // Check if MediaRecorder is supported
      if (!MediaRecorder.isTypeSupported('audio/webm;codecs=opus')) {
        console.warn('WebM with Opus not supported, trying alternative format');
      }

      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true
        } 
      });

      mediaStreamRef.current = stream;

      const mimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus') 
        ? 'audio/webm;codecs=opus' 
        : 'audio/webm';

      const mediaRecorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        try {
          const audioBlob = new Blob(audioChunksRef.current, { type: mimeType });
          await processAudioData(audioBlob);
          audioChunksRef.current = [];
        } catch (error) {
          console.error('Error processing audio on stop:', error);
        }
      };

      mediaRecorder.onerror = (event) => {
        console.error('MediaRecorder error:', event);
        setError('Audio recording error');
      };

      // Start recording in chunks
      mediaRecorder.start(1000); // 1 second chunks
      setIsRecording(true);

      console.log('Audio recording started');

    } catch (error) {
      console.error('Error starting audio recording:', error);
      setError('Failed to access microphone. Please check permissions.');
    }
  };

  const processAudioData = async (audioBlob: Blob) => {
    try {
      // Convert blob to base64
      const arrayBuffer = await audioBlob.arrayBuffer();
      const base64Audio = btoa(String.fromCharCode(...new Uint8Array(arrayBuffer)));

      // Send to backend via WebSocket
      if (websocketRef.current && websocketRef.current.readyState === WebSocket.OPEN) {
        websocketRef.current.send(JSON.stringify({
          type: 'audio_data',
          audio_data: base64Audio,
          interview_id: interviewId || agentId
        }));
      }

      // Also send via LiveKit data channel if available
      if (roomRef.current && roomRef.current.isConnected) {
        const data = JSON.stringify({
          type: 'audio_data',
          audio_data: base64Audio,
          timestamp: new Date().toISOString()
        });

        try {
          await roomRef.current.localParticipant.publishData(
            new TextEncoder().encode(data),
            DataPacket_Kind.RELIABLE
          );
        } catch (error) {
          console.error('Error sending data via LiveKit:', error);
        }
      }

    } catch (error) {
      console.error('Error processing audio data:', error);
    }
  };

  const playAudioFromBase64 = (base64Audio: string) => {
    try {
      const audioData = atob(base64Audio);
      const audioArray = new Uint8Array(audioData.length);
      for (let i = 0; i < audioData.length; i++) {
        audioArray[i] = audioData.charCodeAt(i);
      }

      const audioBlob = new Blob([audioArray], { type: 'audio/wav' });
      const audioUrl = URL.createObjectURL(audioBlob);

      const audio = new Audio(audioUrl);
      audio.onended = () => {
        URL.revokeObjectURL(audioUrl);
      };

      audio.play().catch(error => {
        console.error('Error playing audio:', error);
      });

    } catch (error) {
      console.error('Error playing audio from base64:', error);
    }
  };

  const sendTextMessage = () => {
    const message = prompt('Enter your message:');
    if (message && websocketRef.current && websocketRef.current.readyState === WebSocket.OPEN) {
      websocketRef.current.send(JSON.stringify({
        type: 'text_message',
        message: message
      }));

      // Add to local messages immediately
      setMessages(prev => [...prev, {
        id: `user_${Date.now()}`,
        speaker: 'STUDENT',
        message: message,
        timestamp: new Date().toISOString(),
        type: 'text'
      }]);
    }
  };

  const endSession = () => {
    if (websocketRef.current && websocketRef.current.readyState === WebSocket.OPEN) {
      websocketRef.current.send(JSON.stringify({
        type: 'end_session'
      }));
    }
    cleanup();
    navigate('/dashboard');
  };

  const cleanup = useCallback(() => {
    // Clear reconnection timeout
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    // Stop recording
    if (mediaRecorderRef.current && isRecording) {
      try {
        mediaRecorderRef.current.stop();
      } catch (error) {
        console.error('Error stopping media recorder:', error);
      }
      setIsRecording(false);
    }

    // Stop media stream
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }

    // Disconnect from LiveKit room
    if (roomRef.current) {
      roomRef.current.disconnect();
      roomRef.current = null;
    }

    // Close WebSocket
    if (websocketRef.current) {
      websocketRef.current.close(1000, 'Component unmounting');
      websocketRef.current = null;
    }

    setIsConnected(false);
    setSessionStarted(false);
    setIsMicEnabled(false);
  }, [isRecording]);

  // Cleanup on unmount
  useEffect(() => {
    return () => cleanup();
  }, [cleanup]);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-blue-500 mx-auto"></div>
          <p className="mt-4 text-gray-600">Initializing session...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">
                LiveKit Voice Interview
              </h1>
              <p className="text-gray-600">
                Real-time voice communication with AI interviewer
              </p>
            </div>
            <div className="flex items-center space-x-4">
              <div className={`flex items-center space-x-2 ${isConnected ? 'text-green-600' : 'text-red-600'}`}>
                <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <span className="font-medium">{isConnected ? 'Connected' : 'Disconnected'}</span>
              </div>
              {isRecording && (
                <div className="flex items-center space-x-2 text-red-600">
                  <div className="w-3 h-3 rounded-full bg-red-500 animate-pulse"></div>
                  <span className="font-medium">Recording</span>
                </div>
              )}
              {sessionStarted && (
                <div className="flex items-center space-x-2 text-blue-600">
                  <div className="w-3 h-3 rounded-full bg-blue-500 animate-pulse"></div>
                  <span className="font-medium">Session Active</span>
                </div>
              )}
            </div>
          </div>

          {/* Error Display */}
          {error && (
            <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg">
              <div className="flex items-center">
                <div className="text-red-600 font-medium">Error:</div>
                <div className="ml-2 text-red-700">{error}</div>
              </div>
            </div>
          )}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* LiveKit Audio Controls */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <h2 className="text-lg font-semibold mb-4">Audio Controls</h2>

            <div className="space-y-4">
              <div className="flex items-center space-x-4">
                <button
                  onClick={enableMicrophone}
                  disabled={!roomRef.current || isMicEnabled}
                  className={`px-4 py-2 rounded-lg ${
                    isMicEnabled 
                      ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                      : 'bg-green-500 text-white hover:bg-green-600'
                  }`}
                >
                  {isMicEnabled ? 'Mic Enabled' : 'Enable Mic'}
                </button>
                <button
                  onClick={disableMicrophone}
                  disabled={!roomRef.current || !isMicEnabled}
                  className={`px-4 py-2 rounded-lg ${
                    !isMicEnabled 
                      ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                      : 'bg-red-500 text-white hover:bg-red-600'
                  }`}
                >
                  Disable Mic
                </button>
              </div>

              <div className="flex items-center space-x-4">
                <button
                  onClick={sendTextMessage}
                  disabled={!isConnected}
                  className="bg-blue-500 text-white px-4 py-2 rounded-lg hover:bg-blue-600 disabled:bg-gray-300 disabled:cursor-not-allowed"
                >
                  Send Text Message
                </button>
                <button
                  onClick={endSession}
                  className="bg-red-500 text-white px-4 py-2 rounded-lg hover:bg-red-600"
                >
                  End Session
                </button>
              </div>

              <div className="text-sm text-gray-600 space-y-1">
                <p>Recording: {isRecording ? 'Active' : 'Inactive'}</p>
                <p>LiveKit: {roomRef.current?.isConnected ? 'Connected' : 'Disconnected'}</p>
                <p>WebSocket: {isConnected ? 'Connected' : 'Disconnected'}</p>
                <p>Microphone: {isMicEnabled ? 'Enabled' : 'Disabled'}</p>
              </div>
            </div>

            {/* Hidden audio element for remote audio */}
            <audio id="remote-audio" autoPlay style={{ display: 'none' }} />
          </div>

          {/* Messages */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <h2 className="text-lg font-semibold mb-4">Conversation</h2>

            <div className="h-64 overflow-y-auto mb-4 border rounded-lg p-4">
              {messages.length === 0 ? (
                <div className="text-center text-gray-500">
                  <p>Waiting for AI interviewer...</p>
                </div>
              ) : (
                <div className="space-y-2">
                  {messages.map((message) => (
                    <div
                      key={message.id}
                      className={`p-2 rounded-lg ${
                        message.speaker === 'STUDENT'
                          ? 'bg-blue-100 ml-8'
                          : 'bg-gray-100 mr-8'
                      }`}
                    >
                      <div className="text-xs text-gray-500">
                        {message.speaker} - {new Date(message.timestamp).toLocaleTimeString()}
                      </div>
                      <div className="text-sm">{message.message}</div>
                    </div>
                  ))}
                  <div ref={messagesEndRef} />
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Feedback */}
        {feedback && (
          <div className="bg-white rounded-lg shadow-sm p-6 mt-6">
            <h2 className="text-lg font-semibold mb-4">Interview Feedback</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-blue-50 p-4 rounded-lg">
                <h3 className="font-semibold">Overall Score</h3>
                <p className="text-2xl font-bold text-blue-600">{feedback.overall_score}/10</p>
              </div>
              <div className="bg-green-50 p-4 rounded-lg">
                <h3 className="font-semibold">Strengths</h3>
                <ul className="text-sm">
                  {feedback.strengths?.map((strength: string, index: number) => (
                    <li key={index}>• {strength}</li>
                  ))}
                </ul>
              </div>
              <div className="bg-yellow-50 p-4 rounded-lg">
                <h3 className="font-semibold">Improvements</h3>
                <ul className="text-sm">
                  {feedback.improvements?.map((improvement: string, index: number) => (
                    <li key={index}>• {improvement}</li>
                  ))}
                </ul>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default LiveKitInterview;
